{
  "title": "Time To Live (TTL)",
  "group": "DynamoDB फीचर्स",
  "options": [
    {
      "text": "एक्सपायर होते ही आइटम्स को तुरंत डिलीट कर देता है",
      "hint": "तुरंत डिलीशन डीबी परफॉर्मेंस को प्रभावित कर सकता है।"
    },
    {
      "text": "मैन्युअल डिलीशन ट्रिगर की आवश्यकता होती है",
      "hint": "TTL का मकसद ही ऑटोमेशन है।"
    },
    {
      "text": "बेस्ट-एफर्ट टाइमिंग के साथ बैकग्राउंड डिलीशन",
      "hint": "सही! बैकग्राउंड प्रोसेसिंग से परफॉर्मेंस सुरक्षित रहती है।"
    },
    {
      "text": "आइटम्स को एक्सपायर करता है लेकिन स्टोर रखता है",
      "hint": "एक्सपायर होने के बाद डेटा स्टोरेज से हट जाता है।"
    }
  ],
  "questionProse": [
    "DynamoDB का TTL फीचर आइटम डिलीशन को वास्तव में कैसे हैंडल करता है?"
  ],
  "explanationProse": [
    "DynamoDB TTL की विशेषताएं:\n      - एक बैकग्राउंड प्रोसेस TTL एट्रिब्यूट को मॉनिटर करता है\n      - एक्सपायर्ड आइटम्स को बेस्ट-एफर्ट बेसिस पर डिलीट किया जाता है, आमतौर पर कुछ दिनों के भीतर। ऐसा इसलिए किया जाता है ताकि डेटाबेस की परफॉर्मेंस पर कोई अतिरिक्त लोड न पड़े।\n      - TTL फीचर के लिए कोई अतिरिक्त कॉस्ट नहीं आती\n      - डिलीट हुए आइटम्स DynamoDB Streams में कैप्चर हो जाते हैं\n\n      बेस्ट यूज़ केसेस:\n      - सेशन मैनेजमेंट\n      - लॉग एक्सपायरेशन\n      - टेम्पररी डेटा क्लीनअप\n      - रेगुलेटरी कंप्लायंस"
  ]
}
